{
  "handoff_brief": {
    "recipient": "Shaq",
    "task_context": "Implement API rate limiting middleware. Four agents have converged on requirements, architecture, and operational constraints. One significant design correction was identified during review and is resolved below — use the corrected approach.",
    "domain_rules": [
      {
        "rule": "Rate limit is 100 requests per 60-second rolling window per API key",
        "testable_assertion": "Given API key K has made 100 requests in the last 60 seconds, the next request from K returns HTTP 429"
      },
      {
        "rule": "HTTP 429 responses include a Retry-After header with seconds until the caller can retry",
        "testable_assertion": "The Retry-After value equals the number of seconds remaining until the oldest request in the current window falls outside the 60-second sliding window"
      },
      {
        "rule": "The rate limit window resets on a rolling basis, not at fixed intervals",
        "testable_assertion": "If 100 requests are made at t=0 and the 101st at t=30, it is rejected; but if attempted at t=61, it succeeds because the t=0 requests have aged out"
      },
      {
        "rule": "Rate limiter must fail open if Redis is unavailable",
        "testable_assertion": "If Redis is down, all requests are allowed through and redis_unavailable_total metric increments"
      }
    ],
    "architecture_guidance": [
      {
        "decision": "Use Redis sorted sets for a true sliding window (NOT fixed window counters)",
        "implementation_note": "Key pattern: rate_limit:{api_key}. Use ZADD with timestamp as score, ZREMRANGEBYSCORE to evict entries older than 60s, ZCARD to count. This avoids the boundary-burst problem identified in review. Each entry can use a unique member (e.g., UUID or timestamp+nonce)."
      },
      {
        "decision": "Set a TTL of 60 seconds on the sorted set key as a safety net",
        "implementation_note": "The TTL prevents orphaned keys if a caller stops sending requests. Reset the TTL on each request with EXPIRE."
      },
      {
        "decision": "Middleware runs before all authenticated routes",
        "implementation_note": "The API key must be extracted before the rate limit check. Place the middleware after authentication but before route handlers."
      },
      {
        "decision": "Retry-After is computed dynamically, not hardcoded",
        "implementation_note": "Compute as: (oldest_request_timestamp_in_window + 60) - now. This tells the caller exactly when the oldest entry ages out and a slot opens."
      },
      {
        "decision": "Fail-open on Redis unavailability",
        "implementation_note": "Wrap all Redis calls in try/catch. On any Redis error, allow the request through, log a warning, and increment redis_unavailable_total counter. Do NOT cache rate limit state in-process as a fallback — just allow."
      }
    ],
    "acceptance_criteria": [
      {
        "criterion": "101st request in window is rejected",
        "given": "An API key has made 100 requests in the last 60 seconds",
        "when": "The 101st request arrives",
        "then": "HTTP 429 is returned with a Retry-After header containing seconds until the oldest request ages out"
      },
      {
        "criterion": "Window rolls correctly (no boundary burst)",
        "given": "An API key made 50 requests at t=0 and 50 requests at t=30",
        "when": "A request arrives at t=45",
        "then": "HTTP 429 is returned because all 100 are within the trailing 60-second window"
      },
      {
        "criterion": "Window rolls correctly (requests age out)",
        "given": "An API key made 100 requests at t=0",
        "when": "A request arrives at t=61",
        "then": "The request succeeds because all t=0 requests have aged out of the 60-second window"
      },
      {
        "criterion": "Fail-open when Redis is unavailable",
        "given": "Redis is unreachable",
        "when": "Any request arrives",
        "then": "The request is allowed through and redis_unavailable_total metric is incremented"
      },
      {
        "criterion": "Observability metrics are emitted",
        "given": "Rate limiting is active",
        "when": "A request is rate-limited OR Redis is unavailable",
        "then": "rate_limit_exceeded_total or redis_unavailable_total counters increment respectively"
      }
    ],
    "terminology_alignment": [
      {
        "domain_term": "rolling window",
        "technical_term": "sliding window via Redis sorted set",
        "definition": "A 60-second window that slides continuously with time. At any moment, only requests from the last 60 seconds count. This is NOT a fixed window that resets at interval boundaries."
      },
      {
        "domain_term": "Retry-After",
        "technical_term": "computed TTL delta",
        "definition": "HTTP response header (integer, seconds). Computed as the time remaining until the oldest tracked request exits the sliding window, freeing a slot."
      },
      {
        "domain_term": "fail open",
        "technical_term": "catch-and-allow pattern",
        "definition": "When the rate limiting infrastructure (Redis) is unavailable, the system defaults to allowing all requests rather than blocking them."
      }
    ],
    "contradictions_resolved": [
      {
        "conflict": "MJ proposed a sliding window counter with key pattern rate_limit:{api_key}:{window_start_unix} and 60s TTL. Kobe's review identified this is actually a fixed window implementation that allows burst-at-boundary (up to 200 requests in a short span straddling two windows). Bird's domain rule explicitly requires a 'rolling window'.",
        "resolution": "Adopted Kobe's recommendation: use Redis sorted sets (ZADD/ZREMRANGEBYSCORE/ZCARD) for a true sliding window. This satisfies Bird's rolling window requirement. MJ's key pattern is replaced with a single key per API key (rate_limit:{api_key}) containing timestamped members."
      }
    ],
    "open_questions": []
  },
  "escalations": [],
  "confidence": {
    "level": 92,
    "high_confidence_areas": [
      "Domain rules are clear and unambiguous from Bird",
      "Sorted set approach is well-established for sliding window rate limiting",
      "Fail-open behavior is agreed upon by all agents",
      "Kobe's boundary-burst correction is sound and resolves the MJ/Bird mismatch"
    ],
    "low_confidence_areas": [
      "Exact Redis sorted set member uniqueness strategy (UUID vs timestamp+nonce) — Shaq should pick what fits the stack"
    ],
    "assumptions": [
      "Redis is already available in the infrastructure (no new provisioning needed)",
      "API key is available in the request context before the rate limit middleware runs",
      "A single Redis instance (not clustered) is sufficient for the current scale"
    ]
  }
}

